class Solution {
    public int numberOfSpecialChars(String word) {
        int count = 0;
        boolean[] seenLower = new boolean[26];
        for (char c : word.toCharArray()) {
            if (Character.isLowerCase(c)) {
                seenLower[c - 'a'] = true;
            } else {
                if (seenLower[c - 'A']) {
                    count++;
                }
            }
        }
        return count;
    }
}
